#include<bits/stdc++.h>
using namespace std;
long long fa_bcj[1000010],son[1000010],root[1000010],a[1000010],b[1000010],k;
long long find(long long x)
{
    return(x==fa_bcj[x]?x:fa_bcj[x]=find(fa_bcj[x]));
}
struct segment_tree
{
    struct node
    {
        long long sum;
        long long lson,rson;
    }a[64000010];
    long long cnt;
    segment_tree():cnt(0){}
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        if(l==r)
        {
            a[x].sum=0;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        return x;
    }
    long long update(long long x,long long l,long long r,long long p)
    {
        long long now=++cnt;
        a[now]=a[x];
        a[now].sum++;
        if(l==r)
        {
            return now;
        }
        long long mid=(l+r)>>1;
        if(p<=mid)
        {
            a[now].lson=update(a[x].lson,l,mid,p);
        }
        else
        {
            a[now].rson=update(a[x].rson,mid+1,r,p);
        }
        return now;
    }
    long long query(long long u,long long v,long long lca,long long falca,long long l,long long r,long long k)
    {
        if(l==r)
        {
            return l;
        }
        long long x=a[a[u].lson].sum+a[a[v].lson].sum-a[a[lca].lson].sum-a[a[falca].lson].sum;
        long long mid=(l+r)>>1;
        if(x>=k)
        {
            return query(a[u].lson,a[v].lson,a[lca].lson,a[falca].lson,l,mid,k);
        }
        else
        {
            return query(a[u].rson,a[v].rson,a[lca].rson,a[falca].rson,mid+1,r,k-x);
        }
    }
}t;
vector<long long> mp[1000010];
bool vis[1000010];
long long fa[1000010][41],lg[1000010],d[1000010];
void dfs(long long x,long long f,long long rt)
{
    memset(fa[x],0,sizeof(fa[x]));
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(long long i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    son[rt]++;
    d[x]=d[f]+1;
    vis[x]=true;
    fa_bcj[x]=f;
    root[x]=t.update(root[f],1,k,a[x]);
    for(long long i:mp[x])
    {
        if(i!=f)
        {
            dfs(i,x,rt);
        }
    }
}
long long lca(long long x,long long y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(long long i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
long long query(long long u,long long v,long long k1)
{
    long long l=lca(u,v);
    // printf("l=%lld\n",l);
    long long p=t.query(root[u],root[v],root[l],root[fa[l][0]],1,k,k1);
    // printf("p=%lld root[u]=%lld root[v]=%lld root[l]=%lld root[fa[l][0]]=%lld\n",p,root[u],root[v],root[l],root[fa[l][0]]);
    return b[p];
}
int main()
{
    // freopen("pai.in","r",stdin);
    // freopen("pai.out","w",stdout);
    long long n,m,q;
    scanf("%*lld%lld%lld%lld",&n,&m,&q);
    for(long long i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
        a[i]=b[i];
    }
    for(long long i=1;i<=m;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    sort(b+1,b+1+n);
    k=unique(b+1,b+1+n)-b-1;
    for(long long i=1;i<=n;i++)
    {
        a[i]=lower_bound(b+1,b+1+k,a[i])-b;
        // printf("a[%lld]=%lld\n",i,a[i]);
    }
    root[0]=t.init(1,k);
    for(long long i=1;i<=n;i++)
    {
        if(!vis[i])
        {
            dfs(i,0,i);
            fa_bcj[i]=i;
        }
    }
    long long lstans=0;
    while(q--)
    {
        char op;
        long long x,y,k1;
        cin>>op;
        scanf("%lld%lld%lld",&x,&y,&k1);
        x^=lstans;
        y^=lstans;
        if(op=='Q')
        {
            k1^=lstans;
            int l=lca(x,y);
            printf("%d\n",lstans=b[t.query(root[x],root[y],root[l],root[fa[l][0]],1,k,k1)]);
        }
        else
        {
            mp[x].push_back(y);
            mp[y].push_back(x);
            int u=find(x),v=find(y);
            if(son[u]<son[v])
            {
                swap(u,v);
                swap(x,y);
            }
            dfs(y,x,u);
        }
    }
    return 0;
}
